<template>
  <view class="page-container">
    <!-- 顶部标题栏 -->
    <view class="header">
      <u-icon name="arrow-left" size="24" color="#000000" @click="goBack"></u-icon>
      <text class="title">机构详情</text>
      <view class="placeholder"></view>
    </view>

    <!-- 加载状态 -->
    <view v-if="loading" class="loading-state">
      <u-loading-icon mode="circle"></u-loading-icon>
      <text class="loading-text">加载中...</text>
    </view>

    <!-- 内容区域 -->
    <scroll-view v-else-if="detail" scroll-y class="content-scroll">
      <!-- 封面图片 -->
      <view v-if="detail.coverUrl" class="cover-box">
        <u-image
          :src="detail.coverUrl"
          width="100%"
          height="200px"
          mode="aspectFill"
          @click="previewImage(detail.coverUrl)"
        ></u-image>
      </view>

      <!-- 机构基本信息 -->
      <view class="card">
        <text class="org-name">{{ detail.name }}</text>
        
        <view class="tags-box">
          <u-tag :text="detail.typeName" type="primary" size="mini"></u-tag>
          <u-tag v-if="detail.isFree" text="免费" type="success" size="mini" class="ml-2"></u-tag>
          <u-tag 
            :text="detail.status === 'active' ? '服务中' : '已停业'" 
            :type="detail.status === 'active' ? 'success' : 'info'" 
            size="mini" 
            class="ml-2"
          ></u-tag>
        </view>

        <view class="info-list">
          <view class="info-item">
            <u-icon name="map" size="16"></u-icon>
            <text class="info-text">{{ detail.address || '线上服务' }}</text>
          </view>
          <view class="info-item">
            <u-icon name="phone" size="16"></u-icon>
            <text class="info-text phone-link" @click="makeCall">{{ detail.phone }}</text>
          </view>
          <view class="info-item">
            <u-icon name="clock" size="16"></u-icon>
            <text class="info-text">{{ detail.serviceTime || '请咨询' }}</text>
          </view>
          <view v-if="detail.rating" class="info-item">
            <u-icon name="star" color="#ff976a" size="16"></u-icon>
            <text class="info-text">评分：{{ detail.rating }}</text>
          </view>
        </view>
      </view>

      <!-- 机构描述 -->
      <view v-if="detail.description" class="card mt-3">
        <text class="section-title">机构介绍</text>
        <text class="desc-text">{{ detail.description }}</text>
      </view>

      <!-- 服务项目 -->
      <view v-if="detail.services && detail.services.length > 0" class="card mt-3">
        <text class="section-title">服务项目</text>
        <view class="tags-wrap">
          <u-tag
            v-for="(service, index) in detail.services"
            :key="index"
            :text="service"
            plain
            size="mini"
            class="mr-2 mb-2"
          ></u-tag>
        </view>
      </view>

      <!-- 机构图片 -->
      <view v-if="detail.images && detail.images.length > 0" class="card mt-3">
        <text class="section-title">机构环境</text>
        <view class="images-grid">
          <u-image
            v-for="(img, index) in detail.images"
            :key="index"
            :src="img"
            width="32%"
            height="100px"
            mode="aspectFill"
            @click="previewImage(img)"
            class="grid-item"
          ></u-image>
        </view>
      </view>

      <!-- 咨询师团队 -->
      <view v-if="detail.counselors && detail.counselors.length > 0" class="card mt-3">
        <text class="section-title">咨询师团队</text>
        <u-cell-group>
          <u-cell
            v-for="(counselor, index) in detail.counselors"
            :key="index"
            :title="counselor.name"
            :label="`${counselor.title} · ${counselor.specialty}`"
          />
        </u-cell-group>
      </view>

      <!-- 联系方式 -->
      <view class="card mt-3">
        <text class="section-title">联系方式</text>
        <view class="btn-group">
          <u-button 
            size="small" 
            type="primary" 
            block 
            @click="makeCall"
            class="mb-2"
          >
            拨打电话
          </u-button>
          <u-button 
            v-if="detail.website"
            size="small" 
            plain 
            block 
            @click="openWebsite"
            class="mb-2"
          >
            复制官网链接
          </u-button>
          <u-button 
            v-if="detail.address"
            size="small" 
            plain 
            block 
            @click="openNavigation"
          >
            导航前往
          </u-button>
        </view>
      </view>

      <!-- 操作按钮 -->
      <view class="card mt-3">
        <u-button 
          plain 
          block 
          @click="goBack"
        >
          返回列表
        </u-button>
      </view>
      
      <view class="bottom-spacer"></view>
    </scroll-view>

    <!-- 空状态 -->
    <u-empty v-else mode="data" description="机构不存在或已停业"></u-empty>
  </view>
</template>

<script setup lang="ts">
import { ref } from 'vue'
import { onLoad } from '@dcloudio/uni-app'
import request from '@/utils/request'

// 类型定义
interface Counselor {
  name: string
  title: string
  specialty: string
}

interface OrganizationDetail {
  id: number
  name: string
  type: string
  typeName: string
  region: string
  regionCode: string
  address: string
  contact: string
  phone: string
  email: string
  website: string
  isFree: boolean
  serviceTime: string
  description: string
  services: string[]
  rating: number
  coverUrl: string
  images: string[]
  counselors: Counselor[]
  status: string
  latitude?: number
  longitude?: number
}

// 响应式数据
const detail = ref<OrganizationDetail | null>(null)
const loading = ref<boolean>(false)
const organizationId = ref<number | null>(null)

// 加载详情
const loadDetail = async (id: number) => {
  loading.value = true
  try {
    const res = await request.get(`/api/resource/rehab/psychological/organizations/${id}`)
    detail.value = res.data || res.data
  } catch (error) {
    uni.__f__('error','at pages/resource/rehab/OrganizationDetail.vue:218','加载机构详情失败:', error)
    detail.value = null
    uni.showToast({ title: '加载失败，请重试', icon: 'none' })
  } finally {
    loading.value = false
  }
}

// 预览图片
const previewImage = (currentUrl: string) => {
  if (!detail.value) return
  
  const imageList: string[] = []
  if (detail.value.coverUrl) {
    imageList.push(detail.value.coverUrl)
  }
  if (detail.value.images && detail.value.images.length > 0) {
    imageList.push(...detail.value.images)
  }

  if (imageList.length === 0) return

  const currentIndex = imageList.indexOf(currentUrl)

  uni.previewImage({
    urls: imageList,
    current: currentIndex >= 0 ? currentIndex : 0
  })
}

// 拨打电话
const makeCall = () => {
  if (!detail.value?.phone) return
  
  uni.showModal({
    title: '拨打机构电话',
    content: `确定拨打 ${detail.value.name}：${detail.value.phone} 吗？`,
    confirmText: '拨打',
    cancelText: '取消',
    success: (res) => {
      if (res.confirm) {
        uni.makePhoneCall({
          phoneNumber: detail.value!.phone,
          fail: () => {
            uni.showToast({ title: '拨打失败', icon: 'none' })
          }
        })
      }
    }
  })
}

// 访问官网 (复制链接)
const openWebsite = () => {
  if (!detail.value?.website) return
  
  uni.setClipboardData({
    data: detail.value.website,
    success: () => {
      uni.showModal({
        title: '提示',
        content: '官网链接已复制，请在浏览器中打开',
        showCancel: false
      })
    }
  })
}

// 打开地图导航
const openNavigation = () => {
  if (!detail.value) return
  
  // 1. 如果有经纬度，直接导航
  if (detail.value.latitude && detail.value.longitude) {
    uni.openLocation({
      latitude: detail.value.latitude,
      longitude: detail.value.longitude,
      name: detail.value.name,
      address: detail.value.address,
      success: () => {},
      fail: () => {
        uni.showToast({ title: '打开地图失败', icon: 'none' })
      }
    })
  } 
  // 2. 如果只有地址，提示用户复制或手动搜索
  else if (detail.value.address) {
    uni.showModal({
      title: '导航提示',
      content: `地址：${detail.value.address}\n\n小程序无法直接通过地址导航，是否复制地址后手动打开地图APP？`,
      confirmText: '复制地址',
      cancelText: '取消',
      success: (res) => {
        if (res.confirm) {
          uni.setClipboardData({
            data: detail.value!.address,
            success: () => {
              uni.showToast({ title: '地址已复制', icon: 'success' })
            }
          })
        }
      }
    })
  } else {
    uni.showToast({ title: '暂无地址信息', icon: 'none' })
  }
}

// 返回上一页
const goBack = () => {
  uni.navigateBack()
}

// 生命周期
onLoad((options) => {
  // 1. 先检查 options 是否存在
  if (!options || !options.id) {
    uni.showToast({ title: '缺少机构ID', icon: 'none' })
    setTimeout(() => {
      goBack()
    }, 1500)
    return
  }

  // 2. 此时 options.id 一定存在
  organizationId.value = Number(options.id)
  loadDetail(organizationId.value)
})
</script>

